feq[306] = A*B3*D2*w[2]*w[2]*w[3]/C2;
feq[307] = A*B3*D3*w[2]*w[3]*w[3]/C2;
feq[308] = A*B3*w[1]*w[3]*w[3]/(C*D3);
feq[309] = A*B3*w[1]*w[2]*w[3]/(C*D2);
feq[310] = A*B3*w[1]*w[1]*w[3]/(C*D);
feq[311] = A*B3*w[0]*w[1]*w[3]/C;
feq[312] = A*B3*D*w[1]*w[1]*w[3]/C;
feq[313] = A*B3*D2*w[1]*w[2]*w[3]/C;
feq[314] = A*B3*D3*w[1]*w[3]*w[3]/C;
feq[315] = A*B3*w[0]*w[3]*w[3]/D3;
feq[316] = A*B3*w[0]*w[2]*w[3]/D2;
feq[317] = A*B3*w[0]*w[1]*w[3]/D;
feq[318] = A*B3*w[0]*w[0]*w[3];
feq[319] = A*B3*D*w[0]*w[1]*w[3];
feq[320] = A*B3*D2*w[0]*w[2]*w[3];
feq[321] = A*B3*D3*w[0]*w[3]*w[3];
feq[322] = A*B3*C*w[1]*w[3]*w[3]/D3;
feq[323] = A*B3*C*w[1]*w[2]*w[3]/D2;
feq[324] = A*B3*C*w[1]*w[1]*w[3]/D;
feq[325] = A*B3*C*w[0]*w[1]*w[3];
feq[326] = A*B3*C*D*w[1]*w[1]*w[3];
feq[327] = A*B3*C*D2*w[1]*w[2]*w[3];
feq[328] = A*B3*C*D3*w[1]*w[3]*w[3];
feq[329] = A*B3*C2*w[2]*w[3]*w[3]/D3;
feq[330] = A*B3*C2*w[2]*w[2]*w[3]/D2;
feq[331] = A*B3*C2*w[1]*w[2]*w[3]/D;
